// Franjas horarias de 06:00 a 23:00 cada 30 minutos, para el desplegable de horarios
const FRANJAS_HORARIAS = (() => {
  const out = [];
  for (let h = 6; h <= 23; h++) {
    out.push(`${String(h).padStart(2, "0")}:00`);
    if (h < 23) out.push(`${String(h).padStart(2, "0")}:30`);
  }
  return out;
})();

